files.content:
:host {
  display: block;
  flex: 0 0 auto;
  box-sizing: border-box;
  height: 100%;
  min-height: 0;
  overflow: hidden;
  --_panel-tools-rail-width: var(--dimension-size-600);
  --_panel-tools-drawer-width: var(--dimension-panel-width-sm);
  --_panel-tools-border: var(--dimension-stroke-width-012, 1px) solid var(--color-border-tertiary);
  --_panel-tools-surface-bg: var(--color-background-secondary);
  /* Match panel-nav expand timing (medium-1); easing differs by direction. */
  --_panel-tools-expand-dur: var(--effect-animation-duration-medium-1, 300ms);
}

.panel-tools__layout {
  display: flex;
  flex-direction: row-reverse;
  align-items: stretch;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
}

/* Clip frame — only max-width animates (slide reveal, same as pre-rail :host). */
.panel-tools__drawer {
  flex: 0 0 auto;
  max-width: 0;
  min-width: 0;
  height: 100%;
  min-height: 0;
  overflow: hidden;
  box-sizing: border-box;
  transition: none;
}

:host(.panel-tools--ready.panel-tools--motion-opening) .panel-tools__drawer {
  transition: max-width var(--_panel-tools-expand-dur)
    var(--effect-animation-easing-ease-out, ease-out);
}

:host(.panel-tools--ready.panel-tools--motion-closing) .panel-tools__drawer {
  transition: max-width var(--_panel-tools-expand-dur)
    var(--effect-animation-easing-ease-in, ease-in);
}

:host(.panel-tools--open) .panel-tools__drawer {
  max-width: var(--_panel-tools-drawer-width);
}

.panel-tools__drawer--visible {
  border-left: var(--_panel-tools-border);
}

/* Fixed-width surface — stays 400px while the clip frame opens/closes. */
.panel-tools__drawer-surface {
  display: flex;
  flex-direction: column;
  width: var(--_panel-tools-drawer-width);
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
  background-color: var(--_panel-tools-surface-bg);
}

/* Shell-owned chrome (bg + wash) — drawer + rail are transparent frames. */
:host-context(ds-app-shell[gradient]) .panel-tools__drawer-surface,
:host-context(ds-app-shell[gradient]) .panel-tools__rail {
  background-color: transparent;
}

/* Aligns with ds-bar-nav row — same height, inset, border, and title token. */
.panel-tools__header {
  flex: 0 0 auto;
  display: flex;
  align-items: center;
  height: var(--dimension-size-600);
  padding: var(--dimension-space-100);
  border-bottom: var(--_panel-tools-border);
  color: var(--color-foreground-primary);
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

/*
 * Drawer title — match rail action height (size-400) and BarNav heading inset.
 * Use `ds-text.` so scoped specificity beats Text's `:host(.ds-text--inline-box)`
 * (class-only `.panel-tools__title` ties and loses when Text CSS loads later).
 */
ds-text.panel-tools__title {
  display: inline-flex;
  align-items: center;
  height: var(--dimension-size-400);
  padding-inline: var(--dimension-space-100);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/*
 * Fade title + slot body with the drawer slide (same dur/easing).
 * Header border stays opaque — only inner content opacity animates.
 */
ds-text.panel-tools__title,
.panel-tools__body {
  opacity: 0;
  transition: none;
}

:host(.panel-tools--ready.panel-tools--motion-opening) ds-text.panel-tools__title,
:host(.panel-tools--ready.panel-tools--motion-opening) .panel-tools__body {
  transition: opacity var(--_panel-tools-expand-dur)
    var(--effect-animation-easing-ease-out, ease-out);
}

:host(.panel-tools--ready.panel-tools--motion-closing) ds-text.panel-tools__title,
:host(.panel-tools--ready.panel-tools--motion-closing) .panel-tools__body {
  transition: opacity var(--_panel-tools-expand-dur)
    var(--effect-animation-easing-ease-in, ease-in);
}

:host(.panel-tools--open) ds-text.panel-tools__title,
:host(.panel-tools--open) .panel-tools__body {
  opacity: 1;
}

.panel-tools__body {
  flex: 1 1 auto;
  min-height: 0;
  overflow: auto;
  position: relative;
}

/* Skip paint while fully closed; cleared during open/close motion for WYSIWYG slide. */
:host(.panel-tools--drawer-resting) .panel-tools__body {
  content-visibility: auto;
  contain-intrinsic-size: auto 200px;
}

.panel-tools__view {
  display: none;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
  padding: var(--dimension-space-200);
  color: var(--color-foreground-secondary);
  font-family: var(--typography-font-family);
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative-half);
}

.panel-tools__view ::slotted(*) {
  margin: 0;
  color: var(--color-foreground-secondary);
  font-family: var(--typography-font-family);
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative-half);
}

.panel-tools__view--active {
  display: block;
}

/* Rail — mirrors collapsed panel-nav width, padding, and item rhythm. */
.panel-tools__rail {
  flex: 0 0 var(--_panel-tools-rail-width);
  width: var(--_panel-tools-rail-width);
  min-width: var(--_panel-tools-rail-width);
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
  height: 100%;
  min-height: 0;
  border-left: var(--_panel-tools-border);
  background-color: var(--_panel-tools-surface-bg);
}

.panel-tools__rail-header {
  display: flex;
  align-items: center;
  justify-content: center;
  height: var(--dimension-size-600);
  padding: var(--dimension-space-100);
  flex-shrink: 0;
  box-sizing: border-box;
  border-bottom: var(--_panel-tools-border);
}

.panel-tools__rail-body {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
  overflow-x: hidden;
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
  padding: var(--dimension-space-100);
  box-sizing: border-box;
  scrollbar-width: none;
}

.panel-tools__rail-body::-webkit-scrollbar {
  display: none;
}

/* Flush to the bottom of the rail — mirrors Search header pin. */
.panel-tools__rail-footer {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  margin-top: auto;
  padding: var(--dimension-space-100);
  box-sizing: border-box;
}

.panel-tools__rail-action {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: var(--dimension-size-400);
  flex-shrink: 0;
}

import { Component, Prop, Event, EventEmitter, Element, State, Watch, Method, h, Host } from '@stencil/core';
import type { ChromeTransitionDetail } from '../../nav/chrome-transition';
import {
  PANEL_TOOLS_FOOTER_TOOL_ID,
  PANEL_TOOLS_LABELS,
  PANEL_TOOLS_PRIMARY_TOOL_ID,
  type PanelToolsItem,
  type PanelToolsToolId,
} from './panel-tools-types';
import { parsePanelToolsItems, panelToolsDrawerResting, resolvePanelToolActivation } from './panel-tools-utils';

@Component({
  tag: 'ds-panel-tools',
  styleUrl: 'PanelTools.css',
  scoped: true,
})
export class PanelTools {
  @Element() el!: HTMLElement;

  /** When false, only the icon rail is shown. */
  @Prop({ mutable: true, reflect: true }) open: boolean = false;

  /** Active tool view — `search`, `agents`, `messages`, `stacks`, `activity`, or `help`. */
  @Prop({ mutable: true, attribute: 'active-tool', reflect: true })
  activeTool: PanelToolsToolId | '' = '';

  /**
   * Rail items rendered in the right column.
   * Set via JS property: `el.items = [...]`. Replace the array reference to update.
   */
  @Prop() items: PanelToolsItem[] = [];

  /** JSON fallback for `items` — useful when framework bindings don't propagate arrays. */
  @Prop({ attribute: 'items-json' }) itemsJson: string = '';
  @Prop() toolsLabel: string = 'Tools';
  @Prop() toolShortcutsLabel: string = 'Tool shortcuts';

  /** Emitted when a rail button is toggled. Detail = { id, selected }. */
  @Event({ bubbles: true, composed: true }) dsToolChange!: EventEmitter<{
    id: PanelToolsToolId;
    selected: boolean;
  }>;

  /** Bubbling lifecycle — `ds-bar-nav` defers overflow checks during drawer motion. */
  @Event({ bubbles: true, composed: true })
  dsChromeTransitionStart!: EventEmitter<ChromeTransitionDetail>;

  @Event({ bubbles: true, composed: true })
  dsChromeTransitionEnd!: EventEmitter<ChromeTransitionDetail>;

  /** Arms open vs close easing for the in-flight width transition. */
  @State() private motion: 'opening' | 'closing' | 'idle' = 'idle';

  /** Suppresses width transition until the host has painted its initial open state. */
  @State() private readyForMotion = false;

  @State() private rovingIndex = 0;

  private motionEnableGeneration = 0;

  private get railItems(): PanelToolsItem[] {
    return parsePanelToolsItems(this.items, this.itemsJson);
  }

  private get orderedRailItems(): PanelToolsItem[] {
    const railItems = this.railItems;
    const headerItem = railItems.find(item => item.id === PANEL_TOOLS_PRIMARY_TOOL_ID);
    const footerItem = railItems.find(item => item.id === PANEL_TOOLS_FOOTER_TOOL_ID);
    const bodyItems = railItems.filter(
      item => item.id !== PANEL_TOOLS_PRIMARY_TOOL_ID && item.id !== PANEL_TOOLS_FOOTER_TOOL_ID,
    );
    const ordered: PanelToolsItem[] = [];
    if (headerItem) ordered.push(headerItem);
    ordered.push(...bodyItems);
    if (footerItem) ordered.push(footerItem);
    return ordered;
  }

  disconnectedCallback() {
    this.el.removeEventListener('transitionend', this.handleTransitionEnd);
    this.motionEnableGeneration += 1;
  }

  private deferMotionEnable() {
    if (this.readyForMotion) return;
    const generation = ++this.motionEnableGeneration;
    requestAnimationFrame(() => {
      if (generation !== this.motionEnableGeneration) return;
      requestAnimationFrame(() => {
        if (generation !== this.motionEnableGeneration) return;
        this.readyForMotion = true;
      });
    });
  }

  connectedCallback() {
    this.el.addEventListener('transitionend', this.handleTransitionEnd);
  }

  @Watch('open')
  openChanged(isOpen: boolean, wasOpen?: boolean) {
    if (this.readyForMotion && wasOpen !== undefined && wasOpen !== isOpen) {
      this.motion = isOpen ? 'opening' : 'closing';
      this.dsChromeTransitionStart.emit({
        source: 'panel-tools',
        phase: isOpen ? 'opening' : 'closing',
      });
    }
    this.deferMotionEnable();
  }

  @Watch('activeTool')
  activeToolChanged() {
    this.deferMotionEnable();
  }

  componentDidLoad() {
    this.deferMotionEnable();
  }

  @Watch('items')
  @Watch('itemsJson')
  itemsChanged() {
    this.rovingIndex = 0;
    this.deferMotionEnable();
  }

  private handleTransitionEnd = (event: TransitionEvent) => {
    if (event.target !== this.el.querySelector('.panel-tools__drawer')) return;
    if (event.propertyName !== 'max-width') return;
    this.motion = 'idle';
    this.dsChromeTransitionEnd.emit({ source: 'panel-tools' });
  };

  /** Rail selection follows `open` immediately — independent of the slide animation. */
  private isRailSelected(id: PanelToolsToolId): boolean {
    return this.open && this.activeTool === id;
  }

  /** Drawer body stays mounted while the clip frame animates closed. */
  private isDrawerPresent(): boolean {
    return this.open || this.motion === 'closing';
  }

  private isViewActive(id: PanelToolsToolId): boolean {
    return this.isDrawerPresent() && this.activeTool === id;
  }

  private headerLabel(): string {
    if (!this.isDrawerPresent() || !this.activeTool) return '';
    return PANEL_TOOLS_LABELS[this.activeTool as PanelToolsToolId] ?? '';
  }

  private handleToolChange = (id: PanelToolsToolId) => {
    const next = resolvePanelToolActivation(this.open, this.activeTool, id);
    this.open = next.open;
    this.activeTool = next.activeTool;
    this.dsToolChange.emit({ id, selected: next.selected });
  };

  /** Toggle any rail tool open/closed — shell shortcuts K/A/S/M/N call this. */
  @Method()
  async activateTool(id: PanelToolsToolId) {
    const item = this.railItems.find(entry => entry.id === id);
    if (!item || item.isInactive) return;
    this.handleToolChange(id);
  }

  /** Close the tools drawer when open — used by shell keyboard shortcuts. */
  @Method()
  async closeDrawer() {
    if (!this.open) return;
    const id = this.activeTool;
    this.open = false;
    if (id) {
      this.dsToolChange.emit({ id, selected: false });
    }
  }

  private focusRailAt(index: number) {
    const items = this.orderedRailItems;
    if (!items.length) return;
    const bounded = Math.max(0, Math.min(index, items.length - 1));
    if (bounded === this.rovingIndex) return;
    this.rovingIndex = bounded;
    const actions = Array.from(
      this.el.querySelectorAll<HTMLElement>('.panel-tools__rail-action .button-icon'),
    );
    actions[bounded]?.focus({ preventScroll: true });
  }

  private handleRailKeyDown = (e: KeyboardEvent, index: number) => {
    const items = this.orderedRailItems;
    if (!items.length) return;

    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      this.handleToolChange(items[index].id);
      return;
    }

    if (e.key === 'ArrowDown') {
      if (index >= items.length - 1) return;
      e.preventDefault();
      this.focusRailAt(index + 1);
      return;
    }

    if (e.key === 'ArrowUp') {
      if (index <= 0) return;
      e.preventDefault();
      this.focusRailAt(index - 1);
    }
  };

  private renderRailAction(item: PanelToolsItem, index: number) {
    const label = item.ariaLabel ?? PANEL_TOOLS_LABELS[item.id];
    return (
      <ds-tooltip key={item.id} label={label} side="left" size="sm">
        <ds-button-unfilled variant="icon"
          class="panel-tools__rail-action"
          icon={item.icon}
          isActive={this.isRailSelected(item.id)}
          activeFill={false}
          hasBorder={false}
          dot={item.dot ?? false}
          isInactive={item.isInactive}
          focusTabIndex={index === this.rovingIndex ? 0 : -1}
          aria-label={label}
          pressed={this.isRailSelected(item.id)}
          onFocusin={() => { this.rovingIndex = index; }}
          onKeyDown={(e: KeyboardEvent) => this.handleRailKeyDown(e, index)}
          onDsClick={() => this.handleToolChange(item.id)}
        />
      </ds-tooltip>
    );
  }

  render() {
    const headerLabel = this.headerLabel();
    const orderedRailItems = this.orderedRailItems;
    const headerItem = orderedRailItems.find(item => item.id === PANEL_TOOLS_PRIMARY_TOOL_ID);
    const footerItem = orderedRailItems.find(item => item.id === PANEL_TOOLS_FOOTER_TOOL_ID);
    const bodyItems = orderedRailItems.filter(
      item => item.id !== PANEL_TOOLS_PRIMARY_TOOL_ID && item.id !== PANEL_TOOLS_FOOTER_TOOL_ID,
    );
    const footerIndex = footerItem
      ? (headerItem ? 1 : 0) + bodyItems.length
      : -1;
    const showDrawerChrome = this.isDrawerPresent();
    const drawerResting = panelToolsDrawerResting(this.open, this.motion);

    return (
      <Host
        class={{
          'panel-tools': true,
          'panel-tools--open': this.open,
          'panel-tools--ready': this.readyForMotion,
          'panel-tools--motion-opening': this.motion === 'opening',
          'panel-tools--motion-closing': this.motion === 'closing',
          'panel-tools--drawer-resting': drawerResting,
        }}
        role="complementary"
        aria-label={this.toolsLabel}
      >
        <div class="panel-tools__layout">
          <nav class="panel-tools__rail" aria-label={this.toolShortcutsLabel}>
            {headerItem ? (
              <div class="panel-tools__rail-header">
                {this.renderRailAction(headerItem, 0)}
              </div>
            ) : null}
            <div class="panel-tools__rail-body">
              {bodyItems.map((item, bodyIdx) =>
                this.renderRailAction(item, headerItem ? bodyIdx + 1 : bodyIdx),
              )}
            </div>
            {footerItem ? (
              <div class="panel-tools__rail-footer">
                {this.renderRailAction(footerItem, footerIndex)}
              </div>
            ) : null}
          </nav>

          <div
            class={{
              'panel-tools__drawer': true,
              'panel-tools__drawer--visible': showDrawerChrome,
            }}
            aria-hidden={showDrawerChrome ? null : 'true'}
            inert={showDrawerChrome ? undefined : true}
          >
            <div class="panel-tools__drawer-surface">
              <header class="panel-tools__header">
                <ds-text
                  class="panel-tools__title"
                  as="span"
                  variant="text-body-medium"
                  emphasis
                  color="primary"
                  wrap="nowrap"
                >
                  {headerLabel}
                </ds-text>
              </header>
              <div class="panel-tools__body">
                <div
                  class={{
                    'panel-tools__view': true,
                    'panel-tools__view--active': this.isViewActive('search'),
                  }}
                  hidden={!this.isViewActive('search')}
                >
                  <slot name="search" />
                </div>
                <div
                  class={{
                    'panel-tools__view': true,
                    'panel-tools__view--active': this.isViewActive('messages'),
                  }}
                  hidden={!this.isViewActive('messages')}
                >
                  <slot name="messages" />
                </div>
                <div
                  class={{
                    'panel-tools__view': true,
                    'panel-tools__view--active': this.isViewActive('stacks'),
                  }}
                  hidden={!this.isViewActive('stacks')}
                >
                  <slot name="stacks" />
                </div>
                <div
                  class={{
                    'panel-tools__view': true,
                    'panel-tools__view--active': this.isViewActive('activity'),
                  }}
                  hidden={!this.isViewActive('activity')}
                >
                  <slot name="activity" />
                </div>
                <div
                  class={{
                    'panel-tools__view': true,
                    'panel-tools__view--active': this.isViewActive('agents'),
                  }}
                  hidden={!this.isViewActive('agents')}
                >
                  <slot name="agents" />
                </div>
                <div
                  class={{
                    'panel-tools__view': true,
                    'panel-tools__view--active': this.isViewActive('help'),
                  }}
                  hidden={!this.isViewActive('help')}
                >
                  <slot name="help" />
                </div>
              </div>
            </div>
          </div>
        </div>
      </Host>
    );
  }
}

/** Tool ids for the `ds-panel-tools` rail and drawer views. */
export type PanelToolsToolId =
  | 'search'
  | 'agents'
  | 'messages'
  | 'stacks'
  | 'activity'
  | 'help';

export const PANEL_TOOLS_TOOL_IDS: PanelToolsToolId[] = [
  'search',
  'agents',
  'messages',
  'stacks',
  'activity',
  'help',
];

/** Rail header slot — mirrors panel-nav M logo row. */
export const PANEL_TOOLS_PRIMARY_TOOL_ID: PanelToolsToolId = 'search';

/** Rail footer slot — flush to the bottom of the tools column. */
export const PANEL_TOOLS_FOOTER_TOOL_ID: PanelToolsToolId = 'help';

export const PANEL_TOOLS_LABELS: Record<PanelToolsToolId, string> = {
  search: 'Search',
  messages: 'Messages',
  stacks: 'Stacks',
  activity: 'Activity',
  agents: 'Agents',
  help: 'Help & Support',
};

export interface PanelToolsItem {
  id: PanelToolsToolId;
  /** Icon name for <ds-icon>. */
  icon: string;
  /** Whether this rail button is currently pressed/active. */
  selected?: boolean;
  /** Show a notification dot. */
  dot?: boolean;
  isInactive?: boolean;
  ariaLabel?: string;
}

import { parseJsonArrayProp } from '../BarNav/bar-nav-utils';
import type { PanelToolsItem, PanelToolsToolId } from './panel-tools-types';

export function parsePanelToolsItems(
  items: PanelToolsItem[],
  itemsJson: string,
): PanelToolsItem[] {
  if (itemsJson) {
    return parseJsonArrayProp<PanelToolsItem>(itemsJson, []);
  }
  return items ?? [];
}

export function shouldResyncPanelToolsItems(
  prev: PanelToolsItem[],
  next: PanelToolsItem[],
): boolean {
  if (prev.length !== next.length) return true;
  return next.some((item, index) => {
    const prior = prev[index];
    if (!prior) return true;
    return (
      prior.id !== item.id ||
      prior.icon !== item.icon ||
      prior.selected !== item.selected ||
      prior.dot !== item.dot ||
      prior.isInactive !== item.isInactive ||
      prior.ariaLabel !== item.ariaLabel
    );
  });
}

export type PanelToolsMotion = 'opening' | 'closing' | 'idle';

/** True when the drawer clip is fully closed — safe to skip painting slot content. */
export function panelToolsDrawerResting(open: boolean, motion: PanelToolsMotion): boolean {
  return !open && motion === 'idle';
}

/** Toggle or switch rail tool selection — repeat activation closes the active tool. */
export function resolvePanelToolActivation(
  open: boolean,
  activeTool: PanelToolsToolId | '',
  id: PanelToolsToolId,
): { open: boolean; activeTool: PanelToolsToolId; selected: boolean } {
  if (open && activeTool === id) {
    return { open: false, activeTool: id, selected: false };
  }
  return { open: true, activeTool: id, selected: true };
}
